return ['x-generator'=>'GlotPress/4.0.1','translation-revision-date'=>'2025-05-14 13:49:34+0000','plural-forms'=>'nplurals=3; plural=(n == 1) ? 0 : ((n >= 2 && n <= 4) ? 1 : 2);','project-id-version'=>'Plugins - Payment Plugins for Stripe WooCommerce - Stable (latest release)','language'=>'sk','messages'=>['Click the "%1$s" button to submit your payment information and complete your order.'=>'Kliknutím na "%1$s" tlačidlo odošlete svoje platobné údaje a dokončite objednávku.','%s selected'=>'%s zvolené','A billing phone number is required for this payment.'=>'Pri tejto platbe je potrebné uviesť fakturačné telefónne číslo.','This payment method is currently unavailabe. Reason: %s'=>'Tento spôsob platby je momentálne nedostupný. Dôvod: %s','%s is a required field.'=>'%s je povinné pole.','Shipping %s'=>'Doprava %s','When enabled, a notice with additional payment instructions is shown in the payment method section of the checkout shortcode.'=>'Ak je táto možnosť povolená, v časti spôsobu platby v shortcode pokladne sa zobrazí upozornenie s ďalšími pokynmi k platbe.','Show Payment Notice'=>'Zobraziť oznámenie o platbe','Zip (Stripe) by Payment Plugins'=>'Zip (Stripe) od Payment Plugins','Zip gateway that integrates with your Stripe account.'=>'Zip brána, sa integruje s vaším účtom Stripe.','Zip'=>'Zip','If enabled, Stripe\'s default mandate text will be used. If disabled, the plugin will use it\'s mandate text.'=>'Ak je táto možnosť povolená, použije sa predvolený text mandátu spoločnosti Stripe. Ak je vypnuté, plugin použije svoj text mandátu.','Use Stripe Mandate'=>'Používanie mandátu Stripe','Revolut gateway that integrates with your Stripe account.'=>'Brána Revolut, ktorá sa integruje s vaším účtom Stripe.','Revolut (Stripe) by Payment Plugins'=>'Revolut (Stripe) od Payment Plugins','Revolut'=>'Revolut','MobilePay gateway that integrates with your Stripe account.'=>'Brána MobilePay, ktorá sa integruje s vaším účtom Stripe.','MobilePay (Stripe) by Payment Plugins'=>'MobilePay (Stripe) od Payment Plugins','MobilePay'=>'MobilePay','Cash App gateway that integrates with your Stripe account.'=>'Brána Cash App, ktorá sa integruje s vaším účtom Stripe.','Cash App (Stripe) by Payment Plugins'=>'Cash App (Stripe) od Payment Plugins','Cash App'=>'Cash App','Amazon Pay gateway that integrates with your Stripe account.'=>'Brána Amazon Pay, ktorá sa integruje s vaším účtom Stripe.','Amazon Pay (Stripe) by Payment Plugins'=>'Amazon Pay (Stripe) od Payment Plugins','Amazon Pay'=>'Amazon Pay','This order&rsquo;s status is &ldquo;%s&rdquo;&mdash;it cannot be paid for. Please contact us if you need assistance.'=>'Stav tejto objednávky je &ldquo;%s&rdquo;&mdash;nie je možné ju uhradiť. Ak potrebujete pomoc, kontaktujte nás.','If enabled, a Stripe customer will be created for guest users during checkout.'=>'Ak je táto funkcia povolená, Stripe zákazník bude vytvorený pre hosťovského používateľa v pokladni.','Guest Customer Creation'=>'Vytvorenie hosťujúceho zákazníka','Invalid order ID.'=>'Neplatné ID objednávky.','Invalid order key.'=>'Neplatný kľúč objednávky.','Select all'=>'Vybrať všetko','Select none'=>'Zrušiť výber','Country / Region'=>'Krajina / región','Choose countries / regions&hellip;'=>'Vyberte krajiny / regióny&amp;hellip;',' & billing country is not <strong>%s</strong>'=>'& fakturačná krajina nie je <strong>%s</strong>','Sell to specific countries'=>'Predávať do špecifických krajín','Sell to all countries, except for&hellip;'=>'Predávať do všetkých krajín, okrem &hellip;','Sell to all countries'=>'Predávať do všetkých krajín','Saved Accounts'=>'Uložené účty','New Account'=>'Nový účet','Please fill out all required fields.'=>'Prosím vyplňte všetky povinné polia.','Gateway Name'=>'Názov brány','Cookie nonce is invalid'=>'Cookie nonce je neplatné','Mini Cart'=>'Mini košík','GrabPay gateway that integrates with your Stripe account.'=>'GrabPay brána, ktorá sa integruje do vášho účtu Stripe.','GrabPay'=>'GrabPay','Invalid shipping method format. Expected: index:id'=>'Neplatný formát metódy dopravy. Očakávané: index:id','BECS'=>'BECS','Order %1$s from %2$s'=>'Objednávka %1$s z %2$s','%1$sTest cards%2$s'=>'%1$sTestovacie karty%2$s','Please enter your IBAN before proceeding.'=>'Pred pokračovaním zadajte váš IBAN.','Please select a bank before proceeding'=>'Pred pokračovaním vyberte banku','Please select a payment method before proceeding.'=>'Pred pokračovaním vyberte spôsob platby.','Your card number is incomplete.'=>'Číslo vašej karty je neúplné.','Above add to cart'=>'Nad "pridať do košíka"','Below add to cart'=>'Pod "pridať do košíka"','In order for Apple Pay to display, you must test with an iOS device and have a payment method saved in the Apple Wallet.'=>'Ak chcete, aby sa Apple Pay zobrazoval, musíte ho vyskúšať na zariadení so systémom iOS a mať nejaký spôsob platby uložený v Apple Wallet.','Save'=>'Uložiť','The location of the payment buttons in relation to the Add to Cart button.'=>'Umiestnenie platobných tlačidiel vo vzťahu k tlačidlu Pridať do košíka.','Button Position'=>'Pozícia tlačidla','Move down'=>'Posunúť nadol','Move the "%s" payment method down'=>'Presuňte spôsob platby "%s" nadol','Move up'=>'Posunúť hore','Move the "%s" payment method up'=>'Posuňte spôsob platby "%s" nahor','Method'=>'Metóda','In this section you can control which gateways are displayed on the product page.'=>'V tejto časti môžete určiť, ktoré brány sa zobrazia na stránke produktu.','Stripe Settings'=>'Nastavenia Stripe','If enabled, an email receipt will be sent to the customer by Stripe when the order is processed.'=>'Ak je táto možnosť povolená, zákazníkovi sa pri spracovaní objednávky pošle e-mailom potvrdenie.','Email Receipt'=>'Potvrdenie emailom','Stripe Email Options'=>'Stripe možnosti e-mailu','Increase your conversion rate by offering %1$s on your Product and Cart pages, or at the top of the checkout page. <br/><strong>Note:</strong> you can control which products display %s by going to the product edit page.'=>'Zvýšte svoj konverzný pomer ponúkaním %1$s na svojich stránkach produktu a košíka alebo v hornej časti stránky pokladnice. <br/><strong>Poznámka:</strong> prejdite na stránku úpravy produktu a môžete určiť, ktoré produkty zobrazujú %s.','The card has insufficient funds to complete the purchase.'=>'Karta nemá dostatok finančných prostriedkov na dokončenie nákupu.','The PIN entered is incorrect. '=>'Zadaný PIN je nesprávny.','The payment has been declined as Stripe suspects it is fraudulent.'=>'Platba bola odmietnutá, pretože spoločnosť Stripe má podozrenie, že je podvodná.','The card does not support the specified currency.'=>'Karta nepodporuje zadanú menu.','The customer has exceeded the balance or credit limit available on their card.'=>'Zákazník prekročil zostatok alebo kreditný limit, ktorý má k dispozícii na svojej karte.','The card has been declined for an unknown reason.'=>'Karta bola odmietnutá z neznámeho dôvodu.','The card does not support this type of purchase.'=>'Karta nepodporuje tento typ nákupu.','An error occurred while processing the card. Try again later or with a different payment method.'=>'Pri spracovaní karty sa vyskytla chyba. Skúste to znova neskôr alebo pomocou iného spôsobu platby.','The ZIP code provided was incorrect.'=>'Zadané PSČ bolo nesprávne.','Both a customer and source ID have been provided, but the source has not been saved to the customer. To create a charge for a customer with a specified source, you must first save the card details.'=>'Bol zadaný ID zákazníka aj zdroja, ale zdroj nebol zákazníkovi uložený. Ak chcete vytvoriť poplatok pre zákazníka so zadaným zdrojom, musíte najprv uložiť podrobnosti o karte.','The source cannot be used because it is not in the correct state (e.g., a charge request is trying to use a source with a pending, failed, or consumed source). Check the status of the source you are attempting to use.'=>'Zdroj nemožno použiť, pretože nie je v správnom stave (napr. Žiadosť o poplatok sa pokúša použiť zdroj s čakajúcim, zlyhaným alebo spotrebovaným zdrojom). Skontrolujte stav zdroja, ktorý sa snažíte použiť.','The specified amount is invalid. The charge amount must be a positive integer in the smallest currency unit, and not exceed the minimum or maximum amount.'=>'Zadaná suma je neplatná. Výška poplatku musí byť kladné celé číslo v najmenšej menovej jednotke a nesmie prekročiť minimálnu alebo maximálnu sumu.','The idempotency key provided is currently being used in another request. This occurs if your integration is making duplicate requests simultaneously.'=>'Poskytnutý idempotenčný kľúč sa momentálne používa v inej žiadosti. K tomu dôjde, ak vaša integrácia podáva duplicitné požiadavky súčasne.','The email address is invalid (e.g., not properly formatted). Check that the email address is properly formatted and only includes allowed characters.'=>'E-mailová adresa je neplatná (napr. Nie je správne naformátovaná). Skontrolujte, či je e-mailová adresa správne naformátovaná a či obsahuje iba povolené znaky.','One or more provided parameters was not allowed for the given operation on the Charge. Check our API reference or the returned error message to see which values were not correct for that Charge.'=>'Jeden alebo viac poskytnutých parametrov nebolo pre danú operáciu povolené na Charge. Skontrolujte náš odkaz na API alebo vrátenú chybovú správu, aby ste zistili, ktoré hodnoty pre danú platbu neboli správne.','The charge cannot be captured as the authorization has expired. Auth and capture charges must be captured within seven days.'=>'Poplatok sa nemôže zachytiť, pretože platnosť autorizácie vypršala. Poplatky za autorizáciu a zachytenie musia byť zachytené do siedmich dní.','This charge would cause you to exceed your rolling-window processing limit for this source type. Please retry the charge later, or contact us to request a higher processing limit.'=>'Tento poplatok by spôsobil prekročenie limitu spracovania pre daný typ zdroja. Skúste to znova neskôr alebo nás kontaktujte a požiadajte o vyšší limit spracovania.','The charge you\'re attempting to refund has been charged back. Check the disputes documentation to learn how to respond to the dispute.'=>'Poplatok, ktorý sa snažíte vrátiť, bol naúčtovaný späť. V dokumentácii k sporom sa dozviete, ako na spor reagovať.','The charge you\'re attempting to refund has already been refunded. Update the request to use the ID of a charge that has not been refunded.'=>'Poplatok, ktorý sa snažíte vrátiť, už bol vrátený. Aktualizujte žiadosť o použitie ID poplatku, ktorý nebol vrátený.','The charge you\'re attempting to capture has already been captured. Update the request with an uncaptured charge ID.'=>'Poplatok, ktorý sa snažíte zachytiť, už bol zachytený. Aktualizujte žiadosť pomocou nezachyteného identifikačného čísla poplatku.','This card has been declined too many times. You can try to charge this card again after 24 hours. We suggest reaching out to your customer to make sure they have entered all of their information correctly and that there are no issues with their card.'=>'Táto karta bola príliš často zamietnutá. Túto kartu môžete skúsiť znova účtovať po 24 hodinách. Odporúčame osloviť zákazníka, aby ste sa uistili, že správne vyplnili všetky svoje informácie a či s kartou nie sú problémy.','The bank account cannot be verified, either because the microdeposit amounts provided do not match the actual amounts, or because verification has failed too many times.'=>'Bankový účet nie je možné overiť buď z toho dôvodu, že poskytnuté čiastky mikroúdajov sa nezhodujú so skutočnými sumami, alebo preto, že overenie zlyhalo príliš často.','Your Connect platform is attempting to share an unverified bank account with a connected account.'=>'Vaša platforma Connect sa pokúša zdieľať neoverený bankový účet s pripojeným účtom.','The bank account provided cannot be used for payouts. A different bank account must be used.'=>'Poskytnutý bankový účet sa nemôže použiť na výplaty. Musí sa použiť iný bankový účet.','The bank account provided already exists on the specified Customer object. If the bank account should also be attached to a different customer, include the correct customer ID when making the request again.'=>'Poskytnutý bankový účet už existuje na určenom objekte zákazníka. Ak by mal byť bankový účet pripojený aj k inému zákazníkovi, pri opätovnom zadaní žiadosti uveďte správne ID zákazníka.','The bank account provided can not be used to charge, either because it is not verified yet or it is not supported.'=>'Poskytnutý bankový účet nie je možné použiť na účtovanie poplatkov, pretože ešte nie je overený alebo nie je podporovaný.','The transfer or payout could not be completed because the associated account does not have a sufficient balance available. Create a new transfer or payout using an amount less than or equal to the account\'s available balance.'=>'Prevod alebo platbu nebolo možné dokončiť, pretože priradený účet nemá k dispozícii dostatočný zostatok. Vytvorte nový prevod alebo platbu pomocou čiastky, ktorá je menšia alebo rovná disponibilnému zostatku na účte.','The payment requires authentication to proceed. If your customer is off session, notify your customer to return to your application and complete the payment. If you provided the error_on_requires_action parameter, then your customer should try another card that does not require authentication.'=>'Na vykonanie platby je potrebné overenie. Ak je váš zákazník mimo relácie, informujte zákazníka, aby sa vrátil k svojej žiadosti a dokončil platbu. Ak ste zadali parameter error_on_requires_action, potom by mal váš zákazník vyskúšať inú kartu, ktorá nevyžaduje overenie.','The specified amount is less than the minimum amount allowed. Use a higher amount and try again.'=>'Zadaná suma je menšia ako minimálna povolená suma. Použite väčšie množstvo a skúste to znova.','The specified amount is greater than the maximum amount allowed. Use a lower amount and try again.'=>'Zadané množstvo je väčšie ako maximálne povolené množstvo. Použite menšie množstvo a skúste to znova.','The bank account number provided is invalid (e.g., missing digits). Bank account information varies from country to country. We recommend creating validations in your entry forms based on the bank account formats we provide.'=>'Zadané číslo bankového účtu je neplatné (napr. Chýbajúce číslice). Informácie o bankovom účte sa v jednotlivých krajinách líšia. Odporúčame vám, aby ste vo svojich prihlasovacích formulároch vytvorili overenie na základe poskytnutých formátov bankových účtov.','Your card\'s expiration year is in the past.'=>'Rok vypršania platnosti vašej karty je v minulosti.','The card has been declined.'=>'Karta bola odmietnutá.','The card has expired. Check the expiration date or use a different card.'=>'Platnosť karty vypršala. Skontrolujte dátum exspirácie alebo použite inú kartu.','The card\'s address is incorrect. Check the card\'s address or use a different card.'=>'Adresa karty je nesprávna. Skontrolujte adresu karty alebo použite inú kartu.','The card\'s expiration year is incorrect. Check the expiration date or use a different card.'=>'Rok vypršania platnosti karty je nesprávny. Skontrolujte dátum exspirácie alebo použite inú kartu.','The card\'s expiration month is incorrect. Check the expiration date or use a different card.'=>'Mesiac vypršania platnosti karty je nesprávny. Skontrolujte dátum exspirácie alebo použite inú kartu.','The card\'s security code is invalid. Check the card\'s security code or use a different card.'=>'Bezpečnostný kód karty je neplatný. Skontrolujte bezpečnostný kód karty alebo použite inú kartu.','This value provided to the field contains characters that are unsupported by the field.'=>'Táto hodnota zadaná do poľa obsahuje znaky, ktoré pole nepodporuje.','The card number is invalid. Check the card details or use a different card.'=>'Číslo karty je neplatné. Skontrolujte podrobnosti o karte alebo použite inú kartu.','The card\'s ZIP code is incorrect. Check the card\'s ZIP code or use a different card.'=>'Poštové smerovacie číslo karty je nesprávne. Skontrolujte PSČ alebo použite inú kartu.','The card\'s security code is incorrect. Check the card\'s security code or use a different card.'=>'Bezpečnostný kód karty je nesprávny. Skontrolujte bezpečnostný kód karty alebo použite inú kartu.','The card number is incorrect. Check the card\'s number or use a different card.'=>'Číslo karty je nesprávne. Skontrolujte číslo karty alebo použite inú kartu.','There was an error processing your credit card.'=>'Pri spracovaní vašej kreditnej karty sa vyskytla chyba.','Cannot process payment'=>'Nedá sa spracovať platba','If enabled, credit card errors will be generic when presented to the customer. Merchants may prefer to not provide details on why a card was not accepted for security purposes.'=>'Ak je povolené, chyby kreditnej karty budú pri predložení zákazníkovi všeobecné. Obchodníci môžu radšej neposkytovať podrobnosti o tom, prečo nebola karta prijatá pre bezpečnostné účely.','Generic Errors'=>'Generické chyby','By providing your IBAN and confirming this payment, you are
			authorizing %s and Stripe, our payment service provider, to send instructions to your bank to debit your account
			and your bank to debit your account in accordance with those instructions. You are entitled to a refund from your bank under the
			terms and conditions of your agreement with your bank. A refund must be claimed within 8 weeks starting from the date on which your account was debited.'=>'Poskytnutím svojho čísla IBAN a potvrdením tejto platby
			udeľujete %s , spoločnosti Stripe a nášmu poskytovateľovi platobných služieb, oprávnenie na zaslanie pokynov
			do vašej banky na zaúčtovanie na ťarchu vášho účtu a do vašej banky na zaúčtovanie na ťarchu vášho účtu v súlade s týmito pokynmi. Máte právo na vrátenie prostriedkov od svojej banky podľa
			podmienok vašej dohody s vašou bankou. Vrátenie platby musí byť uskutočnené do 8 týždňov odo dňa, kedy bol váš účet odpočítaný.','GPay Business Console'=>'GPay Business Console','When test mode is enabled, Google Pay will work without a merchant ID, allowing you to capture the necessary screenshots the Google API team needs to approve your integration request.'=>'Ak je povolený testovací režim, služba Google Pay bude fungovať bez identifikačného čísla obchodníka, čo vám umožní zachytiť potrebné snímky obrazovky, ktoré tím Google API potrebuje na schválenie vašej žiadosti o integráciu.','The name of your company that will appear in the SEPA mandate.'=>'Názov vašej spoločnosti, ktorý sa objaví v mandáte SEPA.','Company Name'=>'Názov spoločnosti','SEPA Test Accounts'=>'Testovacie účty SEPA','Force 3D Secure'=>'Vynútite 3D Secure','Stripe internally determines when 3D secure should be presented based on their SCA engine. If <strong>Force 3D Secure</strong> is enabled, 3D Secure will be forced for ALL credit card transactions. In test mode 3D secure only shows for %1$s3DS Test Cards%2$s regardless of this setting.'=>'Stripe interne určuje, kedy má byť 3D Secure použité na základe ich SCA enginu. Ak je povolená možnosť <strong>Vynútiť 3D Secure</strong>, aplikácia 3D Secure bude vynútená pre VŠETKY transakcie kreditných kariet. V testovacom režime sa 3D Secure zobrazuje iba pre testovacie karty %1$s3DS testovacie karty%2$s bez ohľadu na toto nastavenie.','Alipay gateway that integrates with your Stripe account.'=>'Alipay brána, ktorá sa integruje do vášho účtu Stripe.','Alipay'=>'Alipay','FPX gateway that integrates with your Stripe account.'=>'Brána FPX, ktorá sa integruje s vaším účtom Stripe.','FPX'=>'FPX','This is the icon style that appears next to the gateway on the checkout page. Google\'s API team typically requires the With Outline option on the checkout page for branding purposes.'=>'Toto je štýl ikon, ktorý sa zobrazuje vedľa brány na stránke pokladnice. Tím rozhrania API spoločnosti Google zvyčajne vyžaduje možnosť "S obrysom" na stránke pokladnice pre dodržanie podmienok.','Payment Plugins'=>'Payment Plugins','Kind Regards,'=>'S priateľským pozdravom,','At Stripe\'s request, we have updated Stripe for WooCommerce to use the new Stripe Connect integration. This new integration offers even more security. Stripe is requesting that all merchants switch.'=>'Na žiadosť spoločnosti Stripe sme aktualizovali program Stripe for WooCommerce, aby používal novú integráciu služby Stripe Connect. Táto nová integrácia ponúka ešte väčšiu bezpečnosť. Stripe požaduje, aby všetci obchodníci prešli na inú službu.','Greetings from Payment Plugins,'=>'Pozdravujeme z Payment Plugins,','Stripe For WooCommerce Update'=>'Stripe For WooCommerce aktualizácia','You are not authorized to update this order.'=>'Nemáte oprávnenie aktualizovať túto objednávku.','Invalid order id provided'=>'Zadané neplatné ID objednávky','Connect Stripe Account'=>'Pripojte účet Stripe','No matches found'=>'Žiadne zhody nenájdené','payment_intent.succeeded webhook received. Payment has been completed.'=>'payment_intent.succeeded webhook bol obdržaný. Platba bola dokončená.','Your Stripe account has been connected to your WooCommerce store. You may now accept payments in Live and Test mode.'=>'Váš účet Stripe bol pripojený k vášmu obchodu WooCommerce. Teraz môžete prijímať platby v režime Live a Test.','We were not able to connect your Stripe account. Reason: %s'=>'Nepodarilo sa nám spojiť váš účet Stripe. Dôvod: %s','Please try again.'=>'Prosím skúste znova.','Click this button to perform a connection test. If successful, your site is connected to Stripe.'=>'Kliknutím na toto tlačidlo vykonáte test pripojenia. Ak je úspešný, ste pripojený k službe Stripe.','We make it easy to connect Stripe to your site. Click the Connect button to go through our connect flow.'=>'Uľahčíme vám pripojenie Stripe k vašim stránkam. Kliknutím na tlačidlo Pripojiť prejdete našim postupom pripojenia.','Click to Connect'=>'Kliknutím sa pripojíte','Account ID'=>'Číslo účtu','Pre-order payment authorized in Stripe. Payment method: %s'=>'Predobjednávka autorizovaná v službe Stripe. Spôsob platby: %s','Click %1$shere%2$s to be redirected to your Stripe API settings page then click the <strong>Click to Connect</strong> button.'=>'Kliknutím na %1$stu%2$s budete presmerovaní na svoju stránku nastavení rozhrania Stripe API a potom kliknite na tlačidlo <strong>Kliknutím prepojíte</strong>.','This is your Stripe Account ID and serves as a unique identifier.'=>'Toto je vaše ID účtu Stripe a slúži ako jedinečný identifikátor.','Discount'=>'Zľava','Fees'=>'Poplatky','Connection test to Stripe was successful. Mode: %s.'=>'Testovanie pripojenia ku Stripe bolo úspešné. Mód: %s.','Mode: %s. Invalid publishable key. Please check your entry.'=>'Mód: %s. Nesprávny verejný kľúč. Prosím skontrolujte vami zadaný údaj.','Connection Test'=>'Test pripojenia','Mode: %s. Invalid secret key. Please check your entry.'=>'Režim: %s. Neplatný tajný kľúč. Skontrolujte vami zadaný údaj.','Thank you for updating Stripe for WooCommerce to version %1$s.'=>'Ďakujeme, že ste aktualizovali Stripe pre WooCommerce na verziu %1$s.','Test Webhook Secret'=>'Testujte Webhook Secret','Live Webhook Secret'=>'Live Webhook Secret','Value'=>'Hodnota','Taxable'=>'Zdanitelné','You can assign a fee to the order for ACH payments. Amount is a static amount and percentage is a percentage of the cart amount.'=>'K platbám ACH môžete priradiť poplatok. Čiastka predstavuje statické množstvo a percento predstavuje percento z košíka.','Percentage'=>'Percento','Amount'=>'Množstvo','None'=>'Žiadne','ACH Fee'=>'ACH poplatok','User must be logged in.'=>'Používateľ musí byť prihlásený.','pin'=>'pin','when required'=>'ak je potrebné','n/a'=>'n/a','Please update you product quantity before paying.'=>'Pred zaplatením aktualizujte množstvo produktu.','New Bank'=>'Nová banka','Saved Banks'=>'Uložené banky','Express Checkout'=>'Expresná platba','Bank Payment'=>'Banková platba','ACH gateway that integrates with your Stripe account.'=>'Brána ACH, ktorá sa integruje do vášho účtu Stripe.','ACH'=>'ACH','Title of the Apple Pay gateway'=>'Názov brány Apple Pay','ACH Display'=>'Zobrazenie ACH','Title of the ACH gateway'=>'Názov brány ACH','ACH Payment'=>'ACH platba','If enabled, your site can accept ACH payments through Stripe.'=>'Ak je povolene, môžu vaše stránky prijímať platby ACH prostredníctvom Stripe.','For US customers only.'=>'Iba pre zákazníkov z USA.','Webhook created in Stripe for %s environment. You can test your webhook by logging in to the Stripe dashboard'=>'Webhook bol vytvorený v prostredí Stripe pre %s prostredie. Webhook môžete vyskúšať po prihlásení sa na informačný panel Stripe','There is already a webhook configured for this site. If you want to delete the webhook, login to your Stripe Dashboard.'=>'Webhook už je pre túto stránku nakonfigurovaný. Ak chcete webhook odstrániť, prihláste sa na informačný panel Stripe.','You must configure your secret key before creating webhooks.'=>'Pred vytvorením webhookov musíte nakonfigurovať svoj tajný kľúč.','Minimalist form'=>'Minimalistický formulár','{bank_name} **** {last4}'=>'{bank_name} **** {last4}','{bank_name} ending in {last4}'=>'{bank_name} končiaca na {last4}','Postal'=>'Poštovné','CVV'=>'CVV','password'=>'heslo','username'=>'používateľské meno','sandbox testing credentials'=>'testovacie údaje sandbox','Charge.succeeded webhook received. Payment has been completed.'=>'Charge.succeeded webhook bol obdržaný. Platba dokončená.','Read through our %1$sdocumentation%2$s to configure ACH payments'=>'Prečítajte si našu  %1$sdokumentáciu%2$s a nakonfigurujte platby ACH','Charge %1$s is pending. Payment Method: %2$s. Payment will be completed once payment_intent.succeeded webhook received from Stripe.'=>'Poplatok %1$s sa čaká. Spôsob platby: %2$s. Platba bude dokončená po prijatí webhooku payment_intent.succeeded od spoločnosti Stripe.